  ('fire-eq-tech-moex-02300', 'fire-eq-tech', 'fire-eq-tech-moex-101-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '依據「滅火器認可基準」，大型乾粉滅火器充填之滅火藥劑應在多少公斤以上？', '["15 kg", "18 kg", "20 kg", "45 kg"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "c32a00193b12", "answer_pdf_sha1": "aa4249021090", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
